const resp = $input.first().json;
const items = resp.data?.affected_items || [];
return items.map(i => ({ json: { title: i.title, result: i.result, remediation: i.remediation, description: i.description, rationale: i.rationale } }));

const resp = $input.first().json;
const items = resp.data?.affected_items || [];
return items.map(i => ({ json: { protocol: i.protocol, ip: i.local?.ip, port: i.local?.port, state: i.state, pid: i.pid, process: i.process } }));

const resp = $input.first().json;
const items = resp.data?.affected_items || [];
return items.map(i => ({ json: { name: i.name, pid: i.pid, user: i.euser, state: i.state, cmd: i.cmd } }));

const agentsResp = $('Live Agents').first().json;
const statsResp = $('Live Manager Stats').first().json;

const conn = agentsResp.data?.connection || {};
const hours = statsResp.data?.affected_items || [];

// Current hour stats
const now = new Date();
const currentHour = now.getHours();
const hourData = hours.find(h => h.hour === currentHour) || hours[hours.length - 1] || {};
const alerts = hourData.alerts || [];

let total = 0, critical = 0, high = 0, medium = 0;
const topRules = [];

for (const a of alerts) {
  total += a.times || 0;
  if (a.level >= 12) critical += a.times || 0;
  else if (a.level >= 8) high += a.times || 0;
  else if (a.level >= 4) medium += a.times || 0;

  if (a.level > 0) {
    topRules.push({ sigid: a.sigid, level: a.level, times: a.times });
  }
}

topRules.sort((a, b) => b.times - a.times);

// All hours for mini trend
const hourlyTrend = hours.map(h => {
  const ha = h.alerts || [];
  let ht = 0, hh = 0;
  for (const a of ha) { ht += a.times; if (a.level >= 7) hh += a.times; }
  return { hour: h.hour, total: ht, high: hh, syscheck: h.syscheck || 0 };
});

return [{
  json: {
    agents_total: conn.total || 0,
    agents_active: conn.active || 0,
    agents_disconnected: conn.disconnected || 0,
    total_alerts: total,
    critical_alerts: critical,
    high_alerts: high,
    medium_alerts: medium,
    top_rules: topRules.slice(0, 15),
    hourly_trend: hourlyTrend,
    current_hour: currentHour,
    timestamp: now.toISOString()
  }
}];

const data = $input.first().json;
const buckets = data.aggregations?.top_rules?.buckets || [];

return buckets.map(b => {
  const hit = b.rule_info?.hits?.hits?.[0]?._source?.rule || {};
  const agents = (b.agents?.buckets || []).map(a => ({
    name: a.key,
    count: a.doc_count
  }));

  return {
    json: {
      rule_id: b.key,
      rule_desc: hit.description || 'Unknown',
      rule_level: hit.level || 0,
      rule_groups: (hit.groups || []).slice(0, 5).join(','),
      hit_count: b.doc_count,
      agents: agents,
      affected_agents: agents.map(a => a.name + '(' + a.count + ')').join(', ')
    }
  };
});

const agentName = $('GET /wazuh/agent-alerts').first().json.query.name;
const query = {
  size: 0,
  query: {bool: {must: [
    {range: {timestamp: {gte: "now-24h"}}},
    {term: {"agent.name": agentName}}
  ]}},
  aggs: {
    by_rule: {
      terms: {field: "rule.id", size: 15, order: {_count: "desc"}},
      aggs: {info: {top_hits: {size: 1, _source: ["rule.description", "rule.level", "rule.groups"]}}}
    },
    by_level: {
      range: {field: "rule.level", ranges: [
        {key: "low", from: 0, to: 7},
        {key: "medium", from: 7, to: 12},
        {key: "high", from: 12, to: 15},
        {key: "critical", from: 15}
      ]}
    },
    recent: {
      top_hits: {size: 50, sort: [{timestamp: "desc"}], _source: ["rule.id", "rule.description", "rule.level", "rule.groups", "timestamp"]}
    },
    hourly: {
      date_histogram: {field: "timestamp", calendar_interval: "hour"},
      aggs: {high_plus: {filter: {range: {"rule.level": {gte: 12}}}}}
    }
  }
};
return [{json: {query: JSON.stringify(query)}}];

const d = $input.first().json;
const aggs = d.aggregations || {};

const severity = {};
for (const b of (aggs.by_level?.buckets || [])) {
  severity[b.key] = b.doc_count;
}

const topRules = (aggs.by_rule?.buckets || []).map(b => {
  const info = b.info?.hits?.hits?.[0]?._source?.rule || {};
  return {
    rule_id: b.key,
    description: info.description || 'Unknown',
    level: info.level || 0,
    groups: (info.groups || []).slice(0, 5).join(','),
    count: b.doc_count
  };
});

const recent = (aggs.recent?.hits?.hits || []).map(h => {
  const s = h._source;
  return {
    rule_id: s.rule?.id,
    description: s.rule?.description,
    level: s.rule?.level,
    timestamp: s.timestamp
  };
});

const hourly = (aggs.hourly?.buckets || []).map(b => ({
  time: b.key_as_string,
  total: b.doc_count,
  high: b.high_plus?.doc_count || 0
}));

return [{json: {
  total_alerts: d.hits?.total?.value || 0,
  severity,
  top_rules: topRules,
  recent_alerts: recent,
  hourly: hourly
}}];

const d = $input.first().json;
const hits = d.hits?.hits || [];
const total = d.hits?.total?.value || 0;

const alerts = hits.map(h => {
  const s = h._source;
  const data = s.data || {};
  const win = data.win?.eventdata || {};
  return {
    agent: s.agent?.name,
    agent_id: s.agent?.id,
    rule_id: s.rule?.id,
    description: s.rule?.description,
    level: s.rule?.level,
    groups: (s.rule?.groups || []).slice(0, 3),
    timestamp: s.timestamp,
    srcip: data.srcip || win.sourceIp || null,
    srcport: data.srcport || null,
    dstip: data.dstip || win.destinationIp || null,
    dsthost: win.destinationHostname || null,
    dns_query: win.queryName || null,
    process: win.image || null
  };
});

const epsBuckets = d.aggregations?.eps?.buckets || [];
const recentBuckets = epsBuckets.slice(-4);
const avgEps = recentBuckets.length > 0
  ? (recentBuckets.reduce((sum, b) => sum + b.doc_count, 0) / (recentBuckets.length * 30)).toFixed(1)
  : 0;

const srcIps = (d.aggregations?.top_src_ips?.buckets || []).map(b => ({
  ip: b.key, count: b.doc_count
}));

// Combine dst IPs from both fields
const dstMap = {};
for (const b of (d.aggregations?.top_dst_ips?.buckets || [])) {
  dstMap[b.key] = (dstMap[b.key] || 0) + b.doc_count;
}
for (const b of (d.aggregations?.win_dst_ips?.buckets || [])) {
  dstMap[b.key] = (dstMap[b.key] || 0) + b.doc_count;
}
const dstIps = Object.entries(dstMap)
  .map(([ip, count]) => ({ ip, count }))
  .sort((a, b) => b.count - a.count);

const dnsQueries = (d.aggregations?.dns_queries?.buckets || []).map(b => ({
  domain: b.key, count: b.doc_count
}));

// Connection map: src IP -> which agents
const connections = (d.aggregations?.connections?.by_src?.buckets || []).map(b => ({
  ip: b.key,
  count: b.doc_count,
  agents: (b.agents?.buckets || []).map(a => a.key)
}));

return [{json: {
  total_5min: total,
  eps: parseFloat(avgEps),
  alerts,
  src_ips: srcIps,
  dst_ips: dstIps,
  dns_queries: dnsQueries,
  connections
}}];

const highResp = $('Insights High Alerts').first().json;
const otherResp = $('Insights Other').first().json;

const highAlerts = (highResp.aggregations?.by_rule?.buckets || []).map(b => {
  const info = b.info?.hits?.hits?.[0]?._source?.rule || {};
  return {
    rule_id: b.key,
    description: info.description || 'Unknown',
    level: info.level || 0,
    groups: (info.groups || []).join(','),
    count: b.doc_count,
    agents: (b.agents?.buckets || []).map(a => ({ name: a.key, count: a.doc_count }))
  };
});

const aggs = otherResp.aggregations || {};

const failedAuth = {
  total: aggs.failed_auth?.doc_count || 0,
  by_ip: (aggs.failed_auth?.by_ip?.buckets || []).map(b => ({
    ip: b.key, count: b.doc_count,
    agents: (b.agents?.buckets || []).map(a => a.key)
  })),
  by_user: (aggs.failed_auth?.by_user?.buckets || []).map(b => ({
    user: b.key, count: b.doc_count,
    agents: (b.agents?.buckets || []).map(a => a.key)
  })),
  by_agent: (aggs.failed_auth?.by_agent?.buckets || []).map(b => ({
    agent: b.key, count: b.doc_count
  }))
};

const privEsc = {
  total: aggs.priv_esc?.doc_count || 0,
  by_agent: (aggs.priv_esc?.by_agent?.buckets || []).map(b => ({
    agent: b.key, count: b.doc_count,
    users: (b.users?.buckets || []).map(u => u.key)
  }))
};

const cves = (aggs.cves?.by_cve?.buckets || []).map(b => ({
  description: b.key,
  count: b.doc_count,
  agents: (b.agents?.buckets || []).map(a => ({ name: a.key, count: a.doc_count }))
}));

const srcIps = (aggs.src_ips?.by_ip?.buckets || []).map(b => ({
  ip: b.key, count: b.doc_count,
  agents: (b.agents?.buckets || []).map(a => a.key)
}));

return [{json: {
  high_alerts: highAlerts,
  failed_auth: failedAuth,
  priv_escalation: privEsc,
  vulnerabilities: cves,
  src_ips: srcIps
}}];

const d = $input.first().json;
const total = d.hits?.total?.value || 0;

const recent = (d.hits?.hits || []).map(h => {
  const s = h._source;
  const data = s.data || {};
  const win = data.win?.eventdata || {};
  return {
    agent: s.agent?.name,
    description: s.rule?.description,
    level: s.rule?.level,
    srcip: data.srcip || win.ipAddress || null,
    user: data.dstuser || data.srcuser || win.targetUserName || null,
    timestamp: s.timestamp
  };
});

const aggs = d.aggregations || {};
const by_agent = (aggs.by_agent?.buckets || []).map(b => ({
  agent: b.key,
  count: b.doc_count,
  first_seen: b.first_seen?.value_as_string || null,
  last_seen: b.last_seen?.value_as_string || null
}));
const by_ip = (aggs.by_src_ip?.buckets || []).map(b => ({
  ip: b.key,
  count: b.doc_count,
  agents: (b.agents?.buckets || []).map(a => a.key),
  first_seen: b.first_seen?.value_as_string || null,
  last_seen: b.last_seen?.value_as_string || null
}));
const by_user = (aggs.by_user?.buckets || []).map(b => ({
  user: b.key,
  count: b.doc_count,
  first_seen: b.first_seen?.value_as_string || null,
  last_seen: b.last_seen?.value_as_string || null
}));
const over_time = (aggs.over_time?.buckets || []).map(b => ({
  date: b.key_as_string, count: b.doc_count
}));

return [{json: { total, recent, by_agent, by_ip, by_user, over_time }}];

const rows = $input.all().map(i => i.json);

// Build per-agent totals and hourly breakdown
const agentTotals = {};
const hourlyData = {};
const agents = new Set();

for (const row of rows) {
  const agent = row.agent_name;
  const hour = row.hour;
  const count = parseInt(row.count);

  agents.add(agent);
  agentTotals[agent] = (agentTotals[agent] || 0) + count;

  if (!hourlyData[hour]) hourlyData[hour] = { hour };
  hourlyData[hour][agent] = count;
}

// Sort agents by total descending
const sortedAgents = Object.entries(agentTotals)
  .sort((a, b) => b[1] - a[1])
  .map(([name, total]) => ({ name, total }));

// Build timeline sorted by hour
const timeline = Object.values(hourlyData)
  .sort((a, b) => a.hour.localeCompare(b.hour))
  .map(entry => {
    // Format hour for display
    const d = new Date(entry.hour);
    const display = d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
    const result = { time: display };
    for (const agent of sortedAgents) {
      result[agent.name] = entry[agent.name] || 0;
    }
    return result;
  });

return [{ json: { agents: sortedAgents, timeline, total: rows.reduce((s, r) => s + parseInt(r.count), 0) } }];
